sources.stylesheets/styles.scss:
@import "normalize";
@import "variables";
@import "navigation";
@import "footer";
@import url("https://fonts.googleapis.com/css?family=Raleway:300,400,700&display=swap");

// Accessorie Styles
.ma {
   margin: auto;
} // Margin Auto

body {
   font-family: "Raleway", sans-serif, Arial;
   font-size: 10px;
   height: 100vh;
}
.page-container {
   min-height: 100vh;
}

main {
   overflow: auto;
   padding-bottom: 90px;
   border: 1px solid red;
   height: 70vh;
}

sources.stylesheets/navigation.scss:
header {
   width: 100%;
   height: 95px;
   background: $l-black;
   .logo {
      padding-left: 1.5rem;
   }
   nav {
      max-width: 1040px;
      height: 95px;
      margin: auto;
      display: flex;
      align-items: center;
      .menu-container {
         display: flex;
         justify-content: flex-end;
         align-items: center;
         width: 100%;
         top: -350px;
         transition: all 0.7s ease-in-out;
         ul.menu:first-child {
            margin-right: 2rem;
         }
         ul.menu {
            @include horizontal-list;
            // @include bor;
            .nav-list:hover {
               filter: contrast(30%);
            }
         }
         .nav-social-icons {
            padding: 0 0.6rem;
            cursor: pointer;
            :hover {
               filter: contrast(30%);
            }
         }
      }
   }
}

// Hamburger Menu Styles
.hamburger {
   position: absolute;
   top: 4.5rem;
   right: 7%;
   margin-left: -2rem;
   margin-top: -45px;
   width: 2rem;
   height: 45px;
   z-index: 5;
   cursor: pointer;
   display: none;
}

.hamburger div {
   position: relative;
   width: 3rem;
   height: 4px;
   border-radius: 3px;
   background-color: $white;
   margin-top: 8px;
   transition: all 0.3s ease-in-out;
}

.hamburger-input {
   display: none;
}

// Hamburger Menu Animations
#toggle:checked + .hamburger .top-bun {
   transform: rotate(-45deg);
   margin-top: 25px;
}
#toggle:checked + .hamburger .bottom-bun {
   opacity: 0;
   transform: rotate(45deg);
}
#toggle:checked + .hamburger .meat {
   transform: rotate(45deg);
   margin-top: -3px;
}

#toggle:checked + .hamburger + .nav {
   top: 0;
   transform: scale(1);
}

@media only screen and (max-width: 900px) {
   .menu-container {
      flex-direction: column;
      position: absolute;
      top: 5rem;
      background: $l-black;
      ul.menu.nav-menu {
         display: flex;
         flex-direction: column;
         text-align: center;
         width: 100%;
         padding: 0;
         a {
            padding: 0;
         }
         li {
            padding: 1rem 0;
            border-bottom: 0.5px solid $ccc;
            width: 100%;
         }
      }
      .menu:nth-child(2) {
         padding-left: 0;
      }
   }
   header nav .menu-container ul.menu:first-child {
      margin: 0;
   }
   .nav-menu a:first-child {
      border-top: 0.5px solid $ccc;
      margin-top: 1rem;
   }
   .hamburger {
      display: block;
   }
}

sources.stylesheets/variables.scss:
// Variables
$l-black: #333;
$white: #fff;
$red: #d50000;
$ccc: #ccc;

// Mixins
@mixin flex-jac {
   display: flex;
   justify-content: center;
   align-items: center;
}

@mixin bor {
   border: 1px solid $red;
}

@mixin reset-list {
   list-style: none;
}

@mixin horizontal-list {
   @include reset-list;

   li {
      display: inline-block;
   }
   a {
      color: $white;
      text-decoration: none;
      font-size: 1rem;
      padding-left: 2rem;
   }
}

sources.stylesheets/footer.scss:
footer {
   height: 100px;
   background: #f5f5f5;
   position: relative;
   margin-top: -100px;
   clear: both;
   box-shadow: rgba(0, 0, 0, 0.1) 0px 1px 3px 0px inset;
   h2 {
      font-size: 1rem;
      padding: 0;
      margin: 0;
      text-align: center;
   }
   .footer-container {
      display: flex;
      justify-content: space-between;
      align-items: center;
      max-width: 1040px;
      margin: auto;
      height: 100%;
      p {
         margin-left: 1rem;
         font-size: 0.8rem;
      }

      ul.menu {
         @include horizontal-list;
         margin-right: 1rem;
         .nav-list:hover {
            filter: contrast(30%);
         }
      }
      ul.menu a {
         color: $l-black;
         font-size: 0.7rem;
         border-top: none;
      }
   }
}
